VALUES
  ('dietitian-moex-09934', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '欲以系統抽樣方式於 4000 人中抽取 100 位樣本。先將全體編號後再抽取亂數號碼為 012，之後抽取出的樣本編號依 序應為下列那一項？', '["12, 112, 212…", "12, 52, 92…", "40, 52, 64…", "100, 112, 124…"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09935', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '相同狀況下比較訪問、郵寄及電話三種問卷調查方法，請問那一種問卷調查方法的回收率會最低？', '["訪問問卷調查方法", "郵寄問卷調查方法", "電話問卷調查方法", "無法比較"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09936', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某小學有六個年級，每年級12班，做成12 支籤後由校長在每年級中各抽出3班，抽到的班級全班同學做24 小時飲 食回憶法之膳食調查。請問這是屬於何種抽樣方法？', '["簡單叢集隨機抽樣", "分層系統隨機抽樣", "分層叢集隨機抽樣", "簡單分層隨機抽樣"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09937', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一種研究中會採取「盲目」設計，研究中給予自願參加者具療效的試劑，而給予對照組不具療效的替代品，以 減少安慰劑效應所造成的研究偏差？', '["橫斷性研究法", "病例對照研究法", "實驗研究法", "世代研究法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09938', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', 'A地區4000名居民中，在民國 90年1月1日檢查有30名罹患HIV陽性病人，民國90年12月31日再度檢查有42 名罹患HIV陽性病人，其中12名為新病人，而該年度無HIV陽性病人死亡。假設該年該地區之出生人數等於死亡人 數，請問A地區於民國90年之HIV發生率為多少？', '["42/4000", "42/3958", "30/3988", "12/3970"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09939', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某研究發現孕婦在懷孕時服用 A 藥與生出先天畸型嬰兒有關，因此研究者蒐集了 1000 名懷孕中的孕婦，紀錄孕婦在 懷孕時期所有的藥物服用狀況，並追蹤其生產時嬰兒是否畸形。請問這是那一種研究方法？', '["世代研究法", "病例對照研究法", "橫斷性研究法", "實驗研究法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09940', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '研究結果發現B型肝炎帶原者，其罹患肝癌危險的勝算比（odds ratio）為36.0（95%信賴區間為20.21~64.13），這表示：', '["B型肝炎帶原者比非帶原者，其罹患肝癌之危險增加35倍", "B型肝炎帶原者一定會罹患肝癌", "B型肝炎帶原與罹患肝癌的危險性是獨立的", "這結果不具有顯著性差異"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09941', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以前曾在嘉義、台南地區近海鄉鎮（北門、學甲、布袋、義竹）發生烏腳病，這是屬於那一類型的疾病？', '["Outbreak", "Endemic", "Pandemic", "Sporadic"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09942', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「台灣地區老人營養健康狀況調查 1999~2000」之調查結果，台灣老人在下列營養素的缺乏率（不包含臨界缺乏 率）以那一項最高？', '["Thiamin", "Folic acid", "Magnesium", "Iron"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09943', 'dietitian', 'dietitian-moex-095-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「國民營養健康狀況變遷調查」（NAHSIT 1993~1996）結果發現，13~18歲男性那一種疾病的發生率最高？', '["Diabetes mellitus", "Hyperuricemia", "Hypercholesterolemia", "Hypertension"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "c3b653f2dce9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
